#include<bits/stdc++.h>
using namespace std;
stack<int>st;int p,n;
int main(void){
	cin>>p;
	while(p--){
		cin>>n;
		int a[n+5],b[n+5],ans=1;
		for(int i=1;i<=n;i++)cin>>a[i];
		for(int i=1;i<=n;i++)cin>>b[i];
		for(int i=1;i<=n;i++){
			st.push(a[i]);
			while((st.top())==b[ans]){
				st.pop(),ans++;
				if(st.empty())break;
			}
		}
		if(st.empty())cout<<"Yes\n";
		else cout<<"No\n";
		while(st.size())st.pop();
	}
	return false;
}
